+    }
+
+    #[test]
+    fn ndcg_empty_retrieved() {
+        assert!((ndcg_at_k(&[], &["a", "b"], 3)).abs() < f64::EPSILON);
+    }
+
+    #[test]
+    fn ndcg_k_zero() {
+        assert!((ndcg_at_k(&["a"], &["a"], 0)).abs() < f64::EPSILON);
+    }
+
+    #[test]
+    fn ndcg_single_relevant_at_rank_1() {
+        let score = ndcg_at_k(&["a"], &["a"], 10);
+        assert!(
