+            "single relevant doc at rank 1 should be 1.0"
+        );
+    }
+
+    #[test]
+    fn ndcg_no_overlap() {
+        let score = ndcg_at_k(&["x", "y", "z"], &["a", "b"], 3);
+        assert!(
+            score.abs() < f64::EPSILON,
+            "no overlap should be 0.0, got {score}"
+        );
